592: 	plugPod := st.MakePod().Name("plug-pod").Namespace(testCtx.NS.Name).Container("pause").
593: 		Req(map[v1.ResourceName]string{v1.ResourceCPU: "40m"}).
594: 		NodeAffinityIn("affinity-key", []string{"affinity-value"}).
